import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [projects, setProjects] = useState([]); // सर्व प्रोजेक्ट्स साठवण्यासाठी
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // १. पेज लोड झाल्यावर आपोआप सर्व डेटा खेचून आणण्यासाठी useEffect
  useEffect(() => {
    const fetchAllProjects = async () => {
      try {
        // तुझ्या backend मधील /api/requests मधून डेटा घेतोय
        const res = await axios.get('http://localhost:5000/api/requests');
        setProjects(res.data);
        setLoading(false);
      } catch (err) {
        setError("❌ डेटा लोड करता आला नाही. सर्व्हर चालू असल्याची खात्री करा.");
        setLoading(false);
      }
    };

    fetchAllProjects();
  }, []);

  return (
    <div className="container-fluid py-5 mt-4 px-lg-5">
      <div className="text-center mb-5">
        <h2 className="fw-bold text-primary">Live Project Tracker</h2>
        <p className="text-muted">येथे आमच्या सर्व क्लायंट्सच्या प्रोजेक्टची सद्यस्थिती (Live Status) दिसेल.</p>
      </div>

      {loading ? (
        <div className="text-center py-5">
          <div className="spinner-border text-primary" role="status"></div>
          <p className="mt-2">प्रोजेक्ट्स लोड होत आहेत...</p>
        </div>
      ) : error ? (
        <div className="alert alert-danger text-center shadow-sm">{error}</div>
      ) : (
        /* २. टेबल फॉरमॅट (Rows & Columns) */
        <div className="card shadow-lg border-0 rounded-4 overflow-hidden">
          <div className="table-responsive">
            <table className="table table-hover align-middle mb-0">
              <thead className="bg-primary text-white">
                <tr>
                  <th className="ps-4 py-3">Client Name</th>
                  <th className="py-3">Service Type</th>
                  <th className="py-3">Progress (%)</th>
                  <th className="py-3">Status</th>
                  <th className="py-3">Payment</th>
                </tr>
              </thead>
              <tbody>
                {projects.length > 0 ? projects.map((proj) => (
                  <tr key={proj._id}>
                    <td className="ps-4 py-3 fw-bold text-dark">{proj.fullName}</td>
                    <td className="py-3">{proj.serviceType}</td>
                    <td className="py-3" style={{ width: '250px' }}>
                      <div className="d-flex align-items-center gap-2">
                        <div className="progress flex-grow-1" style={{ height: '10px', borderRadius: '5px' }}>
                          <div 
                            className={`progress-bar progress-bar-striped progress-bar-animated ${proj.progress === 100 ? 'bg-success' : 'bg-primary'}`} 
                            style={{ width: `${proj.progress}%` }}
                          ></div>
                        </div>
                        <span className="small fw-bold">{proj.progress}%</span>
                      </div>
                    </td>
                    <td className="py-3">
                      <span className={`badge rounded-pill px-3 py-2 ${
                        proj.status === 'Completed' ? 'bg-success' : 
                        proj.status === 'In Progress' ? 'bg-warning text-dark' : 'bg-secondary'
                      }`}>
                        {proj.status}
                      </span>
                    </td>
                    <td className="py-3 fw-bold">
                      <span className={proj.paymentStatus === 'Paid' ? 'text-success' : 'text-danger'}>
                        {proj.paymentStatus}
                      </span>
                    </td>
                  </tr>
                )) : (
                  <tr>
                    <td colSpan="5" className="text-center py-5 text-muted">सध्या कोणतेही प्रोजेक्ट्स उपलब्ध नाहीत.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <div className="mt-4 text-center small text-muted">
        <i className="fas fa-info-circle me-1"></i> 
        हा डेटा रिअल-टाइममध्ये अपडेट केला जातो.
      </div>
    </div>
  );
}

export default ClientDashboard;
